#include <bits/stdc++.h>
using namespace std;
map<int,int> mp;
int n,a[100005],dp[100005],ans;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=a[i];j<<=1)
            if(j&a[i])
                dp[i]=max(dp[i],mp[j]+1);
        ans=max(ans,dp[i]);
        for(int j=1;j<=a[i];j<<=1)
            if(j&a[i])
                mp[j]=max(mp[j],dp[i]);
    }
    printf("%d",ans);
    return 0;
}
